+}
+
+impl IntakeMetadata {
+    #[must_use]
+    fn new(
+        run_name: String,
+        source: String,
+        source_kind: SourceKind,
+        snapshot_dir: &Path,
+        pinned_commit: Option<String>,
+    ) -> Self {
+        Self {
