+            resolved_commit: None,
+            snapshot_dir: snapshot_dir.display().to_string(),
+            source_hash: None,
+            lockfiles: Vec::new(),
+            toolchain: ToolchainFingerprint::default(),
+            error_class: None,
+            error_message: None,
+        }
